const batchItem = $('URL fuer URL verarbeiten').first().json;
const scraped = $input.first();
const config = $('Konfiguration').first().json;

const url = batchItem.url || batchItem.URL || '';
const keyword = batchItem.keyword || batchItem.Keyword || '';
const email_empfaenger = config.email_empfaenger || '';
const zielsprache = config.zielsprache || 'DE';

// Jina AI Reader (native Node): gibt Objekt mit 'content', 'text' oder 'data' zurueck
const s = scraped.json;
let original_content = s.content || s.text || s.data || s.markdown || '';

// Fehler-Fallback
if (!original_content || original_content.length < 50) {
  original_content = `[Scraping fehlgeschlagen oder leerer Content fuer URL: ${url}]`;
}

// Auf max 15000 Zeichen begrenzen
if (original_content.length > 15000) {
  original_content = original_content.slice(0, 15000) + '\n...[gekuerzt]';
}

return [{
  json: {
    url,
    keyword,
    original_content,
    email_empfaenger,
    zielsprache
  }
}];
